3_real_world_example.code:
class Enemy {
  constructor(name) {
    this.name = name;
    this.health = 100;
  }
  attack() { console.log('Generic attack!'); }
}

// Boss inherits everything from Enemy
class Boss extends Enemy {
  constructor(name, weapon) {
    super(name); // MUST call parent constructor first!
    this.weapon = weapon; // Now we can use 'this'
  }

  // Method Overriding (Polymorphism)
  attack() {
    console.log(`Boss attacks with ${this.weapon}!`);
    super.attack(); // We can also call the parent's version of the method
  }
}

const bowser = new Boss('Bowser', 'Fire');
bowser.attack();

